"use client";

import Link from "next/link";
import { usePathname, useRouter } from "next/navigation";
import { UserButton } from "@clerk/nextjs";
import { Search, Bell, ChevronDown, Crown } from "lucide-react";
import { cn } from "@/lib/utils";
import { Input } from "@/components/ui/input";
import { useState } from "react";

const mainLinks = [
  { href: "/dashboard", label: "Explore" },
  { href: "/dashboard/questions", label: "Problems" },
  { href: "/dashboard/contest", label: "Contests" },
  { href: "/dashboard/questions", label: "Discuss" }, // Placeholder - can link to a discuss page later
  { href: "/dashboard/interview", label: "Interview" },
  { href: "/dashboard/analytics", label: "Store", hasDropdown: true },
] as const;

export function TopNav() {
  const pathname = usePathname();
  const router = useRouter();
  const [searchQuery, setSearchQuery] = useState("");
  const [showStoreDropdown, setShowStoreDropdown] = useState(false);

  const handleSearch = (e: React.FormEvent) => {
    e.preventDefault();
    if (searchQuery.trim()) {
      router.push(`/dashboard/questions?search=${encodeURIComponent(searchQuery)}`);
    }
  };

  return (
    <header className="sticky top-0 z-50 border-b bg-background/95 backdrop-blur supports-[backdrop-filter]:bg-background/60">
      <div className="mx-auto flex h-14 max-w-[1400px] items-center justify-between px-4 lg:px-6">
        {/* Logo */}
        <Link href="/dashboard" className="flex items-center gap-2">
          <span className="text-xl font-bold tracking-tight">
            Coding Arena
          </span>
        </Link>

        {/* Navigation Links */}
        <nav className="hidden items-center gap-1 text-sm font-medium lg:flex">
          {mainLinks.map((link, index) => {
            const active =
              pathname === link.href ||
              (link.href !== "/dashboard" && pathname.startsWith(link.href));
            return (
              <div key={`${link.href}-${link.label}-${index}`} className="relative">
                <Link
                  href={link.href}
                  onMouseEnter={() => link.hasDropdown && setShowStoreDropdown(true)}
                  onMouseLeave={() => link.hasDropdown && setShowStoreDropdown(false)}
                  className={cn(
                    "px-3 py-2 rounded-md transition-colors",
                    active
                      ? "text-foreground font-medium"
                      : "text-muted-foreground hover:text-foreground"
                  )}
                >
                  {link.label}
                  {link.hasDropdown && (
                    <ChevronDown className="inline-block ml-1 h-3 w-3" />
                  )}
                </Link>
                {link.hasDropdown && showStoreDropdown && (
                  <div
                    className="absolute top-full left-0 mt-1 w-48 rounded-md border bg-popover p-2 shadow-md"
                    onMouseEnter={() => setShowStoreDropdown(true)}
                    onMouseLeave={() => setShowStoreDropdown(false)}
                  >
                    <Link
                      href="/dashboard/analytics"
                      className="block px-3 py-2 text-sm rounded-md hover:bg-accent"
                    >
                      Analytics
                    </Link>
                    <Link
                      href="/dashboard/race/create"
                      className="block px-3 py-2 text-sm rounded-md hover:bg-accent"
                    >
                      Create Race
                    </Link>
                    <Link
                      href="/dashboard/race/join"
                      className="block px-3 py-2 text-sm rounded-md hover:bg-accent"
                    >
                      Join Race
                    </Link>
                  </div>
                )}
              </div>
            );
          })}
        </nav>

        {/* Search Bar */}
        <form
          onSubmit={handleSearch}
          className="hidden md:flex flex-1 max-w-md mx-4"
        >
          <div className="relative w-full">
            <Search className="absolute left-3 top-1/2 h-4 w-4 -translate-y-1/2 text-muted-foreground" />
            <Input
              type="search"
              placeholder="Search questions..."
              value={searchQuery}
              onChange={(e) => setSearchQuery(e.target.value)}
              className="pl-9 h-9 bg-muted/50 border-muted focus-visible:bg-background"
            />
          </div>
        </form>

        {/* Right Side Actions */}
        <div className="flex items-center gap-2">
          {/* Notification Bell */}
          <button
            className="relative p-2 rounded-md hover:bg-muted transition-colors"
            aria-label="Notifications"
          >
            <Bell className="h-5 w-5 text-muted-foreground" />
            {/* Unread indicator can be added here */}
          </button>

          {/* Premium Button */}
          <Link
            href="/dashboard/analytics"
            className="hidden sm:flex items-center gap-1.5 px-3 py-1.5 rounded-md bg-gradient-to-r from-yellow-500 to-orange-500 text-white text-sm font-medium hover:opacity-90 transition-opacity"
          >
            <Crown className="h-4 w-4" />
            Premium
          </Link>

          {/* User Profile */}
          <UserButton afterSignOutUrl="/" />
        </div>
      </div>
    </header>
  );
}

